// Builds curriculum/lesson-family-homework.js from per-lesson family homework files.
// Interactive take-home practice lives at lessons/<id>/homework.html (generated by
// scripts/generate-homework-html.mjs). Printable backup: lessons/<id>/homework.docx.
import { readFileSync, writeFileSync, readdirSync, existsSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = join(__dirname, "..");
const lessonsDir = join(root, "lessons");
const outFile = join(root, "curriculum", "lesson-family-homework.js");

const LESSON_DIR_RE = /^(\d+)-(\d+)(-flagship)?$/;

function familyHomeworkEntry(id, cfg) {
  const custom = cfg.familyHomework || cfg.family?.homework;
  if (custom === false) return null;

  const lessonDir = join(lessonsDir, id);
  let href = custom?.href;
  if (!href) {
    if (existsSync(join(lessonDir, "homework.html"))) {
      href = `/lessons/${id}/homework.html`;
    } else if (existsSync(join(lessonDir, "homework.docx"))) {
      href = `/lessons/${id}/homework.docx`;
    }
  }
  if (!href) return null;

  const title = custom?.title || custom?.name || "Family Homework";
  return {
    text: `🏠 ${title}`,
    href,
    isFamilyHomework: true,
  };
}

const entries = readdirSync(lessonsDir)
  .filter((d) => LESSON_DIR_RE.test(d))
  .filter((d) => existsSync(join(lessonsDir, d, "config.json")))
  .map((id) => {
    const cfg = JSON.parse(
      readFileSync(join(lessonsDir, id, "config.json"), "utf8"),
    );
    const entry = familyHomeworkEntry(id, cfg);
    return entry ? [id, entry] : null;
  })
  .filter(Boolean)
  .sort((a, b) => {
    const ma = a[0].match(LESSON_DIR_RE);
    const mb = b[0].match(LESSON_DIR_RE);
    return (
      Number(ma[1]) - Number(mb[1]) ||
      Number(ma[2]) - Number(mb[2]) ||
      (a[0].endsWith("-flagship") ? 1 : 0) - (b[0].endsWith("-flagship") ? 1 : 0)
    );
  });

const map = Object.fromEntries(entries);
const mapLiteral = JSON.stringify(map, null, 2);

const js = `// Auto-generated by scripts/generate-lesson-family-homework-map.mjs — do not edit by hand.
// Regenerate: npm run generate-lesson-family-homework-map
window.LESSON_FAMILY_HOMEWORK = ${mapLiteral};
`;
writeFileSync(outFile, js, "utf8");

const hubFile = join(root, "curriculum", "index.html");
const hub = readFileSync(hubFile, "utf8");
const begin = "        // BEGIN_LESSON_FAMILY_HOMEWORK_MAP";
const end = "        // END_LESSON_FAMILY_HOMEWORK_MAP";
const start = hub.indexOf(begin);
const stop = hub.indexOf(end);
if (start === -1 || stop === -1 || stop <= start) {
  throw new Error(
    "curriculum/index.html is missing BEGIN_LESSON_FAMILY_HOMEWORK_MAP / END_LESSON_FAMILY_HOMEWORK_MAP markers",
  );
}
const injected =
  begin +
  " (auto — npm run generate-lesson-family-homework-map)\n" +
  `        var LESSON_FAMILY_HOMEWORK = ${mapLiteral};\n` +
  "        " +
  end;
const patched = hub.slice(0, start) + injected + hub.slice(stop + end.length);
writeFileSync(hubFile, patched, "utf8");

console.log(
  `Wrote ${entries.length} family homework entries to ${outFile} and inlined into curriculum/index.html`,
);
